@app.route("/webhook", methods=["GET"])
def verify():
    mode      = request.args.get("hub.mode")
    token     = request.args.get("hub.verify_token")
    challenge = request.args.get("hub.challenge")
    if mode == "subscribe" and token == VERIFY_TOKEN:
        return challenge, 200
    return "Forbidden", 403

@app.route("/webhook", methods=["POST"])
def receive_message():
    try:
        data    = request.get_json()
        entry   = data.get("entry", [{}])[0]
        changes = entry.get("changes", [{}])[0]
        value   = changes.get("value", {})
        msgs    = value.get("messages", [])

        for msg in msgs:
            wa_id = msg.get("from")
            if msg.get("type") == "text":
                user_text = msg["text"]["body"]
                if wa_id not in CONVERSATIONS:
                    CONVERSATIONS[wa_id] = []
                CONVERSATIONS[wa_id].append({"role": "user", "content": user_text})
                if len(CONVERSATIONS[wa_id]) > 20:
                    CONVERSATIONS[wa_id] = CONVERSATIONS[wa_id][-20:]

                r = requests.post(
                    "https://api.anthropic.com/v1/messages",
                    headers={"x-api-key": CLAUDE_API_KEY, "anthropic-version": "2023-06-01", "content-type": "application/json"},
                    json={"model": "claude-sonnet-4-6", "max_tokens": 1024, "system": SYSTEM_PROMPT, "messages": CONVERSATIONS[wa_id]},
                    timeout=30
                )
                reply = r.json().get("content", [{}])[0].get("text", "")
                if reply:
                    CONVERSATIONS[wa_id].append({"role": "assistant", "content": reply})
                    clean = reply[:reply.find("BOOKING_DATA:")].strip() if "BOOKING_DATA:" in reply else reply
                    send_wa_message(wa_id, clean)
                    if "BOOKING_DATA:" in reply:
                        try:
                            idx = reply.find("BOOKING_DATA:") + len("BOOKING_DATA:")
                            raw = reply[idx:].strip()
                            end_idx = raw.find("}") + 1
                            d = json.loads(raw[:end_idx])
                            import time
                            bid = int(time.time() * 1000)
                            b = {
                                "id": bid,
                                "name": d.get("name", d.get("guest_name", "Guest")),
                                "email": d.get("email", ""),
                                "phone": d.get("phone", "") or f"+{wa_id}",
                                "boat": d.get("boat", d.get("vessel", "")),
                                "date": d.get("date", ""),
                                "guests": d.get("guests", d.get("passengers", "")),
                                "notes": d.get("notes", ""),
                                "status": "new",
                                "fromChat": True,
                                "createdAt": __import__("datetime").datetime.utcnow().isoformat()
                            }
                            save_booking(b)
                        except Exception as ex:
                            print(f"Booking parse error: {ex}")
    except Exception as e:
        print(f"Error: {e}")
    return jsonify({"status": "ok"}), 200

@app.route("/bookings", methods=["GET"])
def get_bookings():
    return jsonify({"bookings": load_bookings()})

@app.route("/bookings", methods=["POST"])
def set_bookings():
    data = request.get_json()
    if data and "bookings" in data:
        replace_all_bookings(data["bookings"])
    return jsonify({"ok": True})

@app.route("/booking/<int:bid>", methods=["DELETE"])
def del_booking(bid):
    delete_booking(bid)
    return jsonify({"ok": True})

@app.route("/booking/<int:bid>", methods=["PUT"])
def update_booking(bid):
    b = request.get_json()
    if b:
        b["id"] = bid
        save_booking(b)
    return jsonify({"ok": True})

@app.route("/", methods=["GET"])
def home():
    import base64 as b64
    return Response(b64.b64decode(DASHBOARD_B64).decode("utf-8"), mimetype="text/html")

@app.route("/chat", methods=["POST"])
def chat():
    try:
        data = request.get_json()
        r = requests.post(
            "https://api.anthropic.com/v1/messages",
            headers={"x-api-key": CLAUDE_API_KEY, "anthropic-version": "2023-06-01", "content-type": "application/json"},
            json={"model": "claude-sonnet-4-6", "max_tokens": 1024, "system": data.get("system",""), "messages": data.get("messages",[])},
            timeout=30
        )
        return jsonify(r.json()), r.status_code
    except Exception as e:
        return jsonify({"error": {"message": str(e)}}), 500

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 8080)))

DASHBOARD_B64 = ""
